import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Solution {
    public static String solve(long n) {
        long n2 = n * n;
        long n3 = n * n * n;

        String hexPart = Integer.toHexString(n2).toUpperCase();
        String base36Part = toBase36(n3);

        return hexPart + base36Part;
    }

    private static String toBase36(long num) {
        if (num == 0) {
            return "0";
        }
        List<Character> digits = new ArrayList<>();
        while (num > 0) {
            long remainder = num % 36;
            if (remainder < 10) {
                digits.add((char) ('0' + remainder));
            } else {
                digits.add((char) ('A' + remainder - 10));
            }
            num = num / 36;
        }
        Collections.reverse(digits);
        StringBuilder sb = new StringBuilder();
        for (char c : digits) {
            sb.append(c);
        }
        return sb.toString();
    }
}
